#include "game/gameplay/QuestGameplaySystem.h"
namespace fw { bool QuestGameplaySystem::HasQuest(const SaveGameProfile& profile, const std::string& questId) const { for(const auto& q:profile.quests) if(q.id==questId) return true; return false; } void QuestGameplaySystem::AcceptQuest(SaveGameProfile& profile, const ContentPipeline& pipeline, const std::string& questId) const { if(HasQuest(profile,questId)) return; const auto* def=pipeline.quests.Find(questId); if(!def) return; QuestEntry q{}; q.id=def->id; q.title=def->title; q.state=QuestProgressState::Active; if(!def->targetItemId.empty()) q.objectives.push_back({"collect_"+def->targetItemId,0,def->targetCount,false}); if(!def->targetEnemyType.empty()) q.objectives.push_back({"kill_"+def->targetEnemyType,0,def->targetCount,false}); profile.quests.push_back(q); } bool QuestGameplaySystem::TryCompleteQuest(SaveGameProfile& profile, const ContentPipeline& pipeline, const std::string& questId) const { const auto* def=pipeline.quests.Find(questId); if(!def) return false; for(auto& q: profile.quests){ if(q.id!=questId) continue; for(auto& obj:q.objectives){ if(!obj.completed) return false; } q.state=QuestProgressState::Completed; } profile.inventory.gold += def->rewardGold; if(!def->rewardItemId.empty()) profile.inventory.items.push_back(def->rewardItemId); return true; } void QuestGameplaySystem::RegisterEnemyKill(SaveGameProfile& profile, const std::string& enemyType) const { for(auto& q: profile.quests){ if(q.state!=QuestProgressState::Active) continue; for(auto& obj:q.objectives){ if(obj.id=="kill_"+enemyType){ obj.current=std::min(obj.required,obj.current+1); obj.completed=(obj.current>=obj.required); } } } } }
